package com.recettealarm.app;
import android.Manifest;import android.graphics.Color;import android.app.*;import android.content.*;import android.database.*;import android.graphics.Typeface;import android.net.*;import android.os.*;import android.provider.Settings;import android.view.*;import android.widget.*;import java.util.*;

public class MainActivity extends Activity{DB db;LinearLayout root,list,chips;EditText search;String q="",category="Tous";String[] cats={"Tous","Tajines","Gâteaux","Plats","Desserts","Jus","Pain","Autres"};TextView statRecipes,statFav,statTime;
 public void onCreate(Bundle b){super.onCreate(b);db=new DB(this);if(Build.VERSION.SDK_INT>=33)requestPermissions(new String[]{Manifest.permission.POST_NOTIFICATIONS},5);askExactAlarm();draw();}
 public void onResume(){super.onResume();if(list!=null){load();renderStats();}}
 void askExactAlarm(){try{if(Build.VERSION.SDK_INT>=31){AlarmManager am=(AlarmManager)getSystemService(ALARM_SERVICE);if(!am.canScheduleExactAlarms())startActivity(new Intent(Settings.ACTION_REQUEST_SCHEDULE_EXACT_ALARM, Uri.parse("package:"+getPackageName())));}}catch(Exception e){}}
 void draw(){root=UI.root(this);root.setPadding(UI.dp(this,18),UI.dp(this,18),UI.dp(this,18),UI.dp(this,86));
  LinearLayout top=UI.row(this);TextView menu=UI.iconBtn(this,"☰");TextView bell=UI.iconBtn(this,"🔔");top.addView(menu);TextView hello=UI.tv(this,"Bonjour Chef 👋\nQue cuisine-t-on aujourd'hui ?",25,Typeface.BOLD);top.addView(hello,new LinearLayout.LayoutParams(0,-2,1));top.addView(bell);root.addView(top);menu.setOnClickListener(v->openMenu());bell.setOnClickListener(v->startActivity(new Intent(this,SettingsActivity.class)));
  LinearLayout hero=UI.glassHero(this,"Smart cooking anti-brûlure","Recettes, alarmes, courses et conversions dans une seule app.");root.addView(hero);
  search=UI.input(this,"🔎 Rechercher une recette, ingrédient...");root.addView(search);search.addTextChangedListener(new android.text.TextWatcher(){public void beforeTextChanged(CharSequence s,int a,int b,int c){}public void onTextChanged(CharSequence s,int a,int b,int c){q=s.toString().toLowerCase();load();}public void afterTextChanged(android.text.Editable e){}});
  LinearLayout quick=UI.row(this);TextView scan=UI.chip(this,"📷 Scan",false),course=UI.chip(this,"🛒 Courses",false),conv=UI.chip(this,"📐 Mesures",false);quick.addView(scan);quick.addView(course);quick.addView(conv);root.addView(quick);scan.setOnClickListener(v->UI.toast(this,"Scan ingrédients prévu en V7"));course.setOnClickListener(v->startActivity(new Intent(this,ShoppingActivity.class)));conv.setOnClickListener(v->showText("Convertisseur",db.conversions()));
  LinearLayout catHead=UI.row(this);catHead.addView(UI.tv(this,"Catégories",20,Typeface.BOLD),new LinearLayout.LayoutParams(0,-2,1));TextView all=UI.tv(this,"Voir tout",14,Typeface.BOLD);all.setTextColor(UI.green);catHead.addView(all);root.addView(catHead);all.setOnClickListener(v->{category="Tous";renderChips();load();});HorizontalScrollView hsv=new HorizontalScrollView(this);hsv.setHorizontalScrollBarEnabled(false);chips=new LinearLayout(this);chips.setOrientation(LinearLayout.HORIZONTAL);hsv.addView(chips);root.addView(hsv);renderChips();
  LinearLayout stats=UI.row(this);statRecipes=stat("🍽","0","Recettes");statFav=stat("❤️","0","Favoris");statTime=stat("⏱","0h","Temps");stats.addView(statRecipes,new LinearLayout.LayoutParams(0,-2,1));stats.addView(statFav,new LinearLayout.LayoutParams(0,-2,1));stats.addView(statTime,new LinearLayout.LayoutParams(0,-2,1));root.addView(stats);renderStats();
  root.addView(UI.tv(this,"Recettes populaires",22,Typeface.BOLD));list=new LinearLayout(this);list.setOrientation(LinearLayout.VERTICAL);root.addView(list);load();
  Button add=UI.limeBtn(this,"+ Nouvelle recette");root.addView(add);add.setOnClickListener(v->startActivity(new Intent(this,EditRecipeActivity.class)));
 }
 TextView stat(String icon,String n,String label){TextView v=UI.center(this,icon+"\n"+n+"\n"+label,13,Typeface.BOLD);v.setBackground(UI.stroke(this,UI.card,UI.dp(this,24),0xffe3e7df));v.setPadding(0,UI.dp(this,10),0,UI.dp(this,10));return v;}
 void renderStats(){if(statRecipes==null)return;int r=db.count("recipes"),ing=db.count("ingredients"),st=db.count("steps"),fav=0,total=0;Cursor c=db.recipes();while(c.moveToNext()){try{fav+=c.getInt(c.getColumnIndexOrThrow("fav"))==1?1:0;total+=c.getInt(c.getColumnIndexOrThrow("time"));}catch(Exception e){}}c.close();statRecipes.setText("🍽\n"+r+"\nRecettes");statFav.setText("❤️\n"+fav+"\nFavoris");statTime.setText("⏱\n"+(total/60)+"h"+(total%60)+"\nTemps");}
 void renderChips(){chips.removeAllViews();for(String c:cats){TextView chip=UI.chip(this,iconFor(c)+" "+c,c.equals(category));chip.setOnClickListener(v->{category=c;renderChips();load();});chips.addView(chip);}}
 String iconFor(String c){if(c.equals("Tajines"))return "🥘";if(c.equals("Gâteaux"))return "🍰";if(c.equals("Jus"))return "🥤";if(c.equals("Desserts"))return "🍮";if(c.equals("Pain"))return "🥖";if(c.equals("Plats"))return "🍽";return "🔥";}
 void load(){if(list==null)return;list.removeAllViews();Cursor c=db.recipesByCategory(category);ArrayList<long[]> ids=new ArrayList<>();ArrayList<String[]> data=new ArrayList<>();while(c.moveToNext()){String title=s(c,"title"),cat=s(c,"category"),img=s(c,"image");int time=c.getInt(c.getColumnIndexOrThrow("time")),serv=c.getInt(c.getColumnIndexOrThrow("servings")),rating=c.getInt(c.getColumnIndexOrThrow("rating"));if(q.length()>0&&!(title.toLowerCase().contains(q)||cat.toLowerCase().contains(q)))continue;ids.add(new long[]{c.getLong(c.getColumnIndexOrThrow("id")),time,serv,rating});data.add(new String[]{title,cat,img});}c.close();if(ids.size()==0){list.addView(UI.smallCard(this,"Aucune recette. Clique sur + Nouvelle recette."));return;}for(int i=0;i<ids.size();i+=2){LinearLayout row=UI.row(this);row.setGravity(Gravity.TOP);row.addView(recipeCard(ids.get(i),data.get(i)),new LinearLayout.LayoutParams(0,-2,1));if(i+1<ids.size())row.addView(recipeCard(ids.get(i+1),data.get(i+1)),new LinearLayout.LayoutParams(0,-2,1));else row.addView(new Space(this),new LinearLayout.LayoutParams(0,1,1));list.addView(row);}}
 View recipeCard(long[] meta,String[] d){long id=meta[0];int time=(int)meta[1],serv=(int)meta[2],rating=(int)meta[3];LinearLayout card=new LinearLayout(this);card.setOrientation(LinearLayout.VERTICAL);card.setBackground(UI.stroke(this,Color.WHITE,UI.dp(this,30),0xffe4e7df));card.setPadding(0,0,0,UI.dp(this,10));LinearLayout.LayoutParams clp=new LinearLayout.LayoutParams(-1,-2);clp.setMargins(UI.dp(this,5),UI.dp(this,5),UI.dp(this,5),UI.dp(this,14));card.setLayoutParams(clp);ImageView img=UI.image(this,d[2],142);card.addView(img);TextView pill=UI.pill(this,"⏱ "+time+" min",UI.green);LinearLayout over=UI.row(this);over.setPadding(UI.dp(this,10),0,UI.dp(this,10),0);over.addView(pill,new LinearLayout.LayoutParams(0,-2,1));TextView fav=UI.center(this,"♡",25,Typeface.BOLD);fav.setTextColor(0xffd01818);over.addView(fav);card.addView(over);TextView cat=UI.tv(this,d[1],12,Typeface.BOLD);cat.setTextColor(UI.green);cat.setPadding(UI.dp(this,12),0,0,0);card.addView(cat);TextView title=UI.tv(this,shorten(d[0]),18,Typeface.BOLD);title.setPadding(UI.dp(this,12),0,UI.dp(this,8),0);card.addView(title);TextView metaTxt=UI.muted(this,"👥 "+serv+" pers.   ⭐ "+rating+"/5",13);metaTxt.setPadding(UI.dp(this,12),0,0,0);card.addView(metaTxt);card.setOnClickListener(v->startActivity(new Intent(this,DetailActivity.class).putExtra("id",id)));return card;}
 String shorten(String s){return s==null?"Recette":s.length()>22?s.substring(0,22)+"...":s;}
 void openMenu(){final String[] items={"🍽 Toutes les recettes","❤️ Favoris","🛒 Liste de courses","📐 Convertisseur mesures","⏱ Mode cuisine test","⚙️ Paramètres","🛠 Admin","➕ Nouvelle recette"};new AlertDialog.Builder(this).setTitle("Menu Recette Alarm").setItems(items,(d,which)->{if(which==0){category="Tous";renderChips();load();}else if(which==1){startActivity(new Intent(this,FavoritesActivity.class));}else if(which==2){startActivity(new Intent(this,ShoppingActivity.class));}else if(which==3){showText("Convertisseur",db.conversions());}else if(which==4){startActivity(new Intent(this,CookingActivity.class));}else if(which==5){startActivity(new Intent(this,SettingsActivity.class));}else if(which==6){startActivity(new Intent(this,AdminActivity.class));}else startActivity(new Intent(this,EditRecipeActivity.class));}).show();}
 void showText(String title,String msg){new AlertDialog.Builder(this).setTitle(title).setMessage(msg).setPositiveButton("OK",null).show();}String s(Cursor c,String col){try{String x=c.getString(c.getColumnIndexOrThrow(col));return x==null?"":x;}catch(Exception e){return "";}}
}
